14009 unsigned BoUpSLP::getVectorElementSize(Value *V) {
14010   // If V is a store, just return the width of the stored value (or value
14011   // truncated just before storing) without traversing the expression tree.
14012   // This is the common case.
14013   if (auto *Store = dyn_cast<StoreInst>(V))
14014     return DL->getTypeSizeInBits(Store->getValueOperand()->getType());
14015 
14016   if (auto *IEI = dyn_cast<InsertElementInst>(V))
14017     return getVectorElementSize(IEI->getOperand(1));
14018 
14019   auto E = InstrElementSize.find(V);
14020   if (E != InstrElementSize.end())
14021     return E->second;
14022 
14023   // If V is not a store, we can traverse the expression tree to find loads
14024   // that feed it. The type of the loaded value may indicate a more suitable
14025   // width than V's type. We want to base the vector element size on the width
14026   // of memory operations where possible.
14027   SmallVector<std::tuple<Instruction *, BasicBlock *, unsigned>> Worklist;
14028   SmallPtrSet<Instruction *, 16> Visited;
14029   if (auto *I = dyn_cast<Instruction>(V)) {
14030     Worklist.emplace_back(I, I->getParent(), 0);
14031     Visited.insert(I);
14032   }
14033 
14034   // Traverse the expression tree in bottom-up order looking for loads. If we
14035   // encounter an instruction we don't yet handle, we give up.
14036   auto Width = 0u;
14037   Value *FirstNonBool = nullptr;
14038   while (!Worklist.empty()) {
14039     auto [I, Parent, Level] = Worklist.pop_back_val();
14040 
14041     // We should only be looking at scalar instructions here. If the current
14042     // instruction has a vector type, skip.
14043     auto *Ty = I->getType();
14044     if (isa<VectorType>(Ty))
14045       continue;
14046     if (Ty != Builder.getInt1Ty() && !FirstNonBool)
14047       FirstNonBool = I;
14048     if (Level > RecursionMaxDepth)
14049       continue;
14050 
14051     // If the current instruction is a load, update MaxWidth to reflect the
14052     // width of the loaded value.
14053     if (isa<LoadInst, ExtractElementInst, ExtractValueInst>(I))
14054       Width = std::max<unsigned>(Width, DL->getTypeSizeInBits(Ty));
14055 
14056     // Otherwise, we need to visit the operands of the instruction. We only
14057     // handle the interesting cases from buildTree here. If an operand is an
14058     // instruction we haven't yet visited and from the same basic block as the
14059     // user or the use is a PHI node, we add it to the worklist.
14060     else if (isa<PHINode, CastInst, GetElementPtrInst, CmpInst, SelectInst,
14061                  BinaryOperator, UnaryOperator>(I)) {
14062       for (Use &U : I->operands()) {
14063         if (auto *J = dyn_cast<Instruction>(U.get()))
14064           if (Visited.insert(J).second &&
14065               (isa<PHINode>(I) || J->getParent() == Parent)) {
14066             Worklist.emplace_back(J, J->getParent(), Level + 1);
14067             continue;
14068           }
14069         if (!FirstNonBool && U.get()->getType() != Builder.getInt1Ty())
14070           FirstNonBool = U.get();
14071       }
14072     } else {
14073       break;
14074     }
14075   }
14076 
14077   // If we didn't encounter a memory access in the expression tree, or if we
14078   // gave up for some reason, just return the width of V. Otherwise, return the
14079   // maximum width we found.
14080   if (!Width) {
14081     if (V->getType() == Builder.getInt1Ty() && FirstNonBool)
14082       V = FirstNonBool;
14083     Width = DL->getTypeSizeInBits(V->getType());
14084   }
14085 
14086   for (Instruction *I : Visited)
14087     InstrElementSize[I] = Width;
14088 
14089   return Width;
