14956 void SLPVectorizerPass::collectSeedInstructions(BasicBlock *BB) {
14957   // Initialize the collections. We will make a single pass over the block.
14958   Stores.clear();
14959   GEPs.clear();
14960 
14961   // Visit the store and getelementptr instructions in BB and organize them in
14962   // Stores and GEPs according to the underlying objects of their pointer
14963   // operands.
14964   for (Instruction &I : *BB) {
14965     // Ignore store instructions that are volatile or have a pointer operand
14966     // that doesn't point to a scalar type.
14967     if (auto *SI = dyn_cast<StoreInst>(&I)) {
14968       if (!SI->isSimple())
14969         continue;
14970       if (!isValidElementType(SI->getValueOperand()->getType()))
14971         continue;
14972       Stores[getUnderlyingObject(SI->getPointerOperand())].push_back(SI);
14973     }
14974 
14975     // Ignore getelementptr instructions that have more than one index, a
14976     // constant index, or a pointer operand that doesn't point to a scalar
14977     // type.
14978     else if (auto *GEP = dyn_cast<GetElementPtrInst>(&I)) {
14979       if (GEP->getNumIndices() != 1)
14980         continue;
14981       Value *Idx = GEP->idx_begin()->get();
14982       if (isa<Constant>(Idx))
14983         continue;
14984       if (!isValidElementType(Idx->getType()))
14985         continue;
14986       if (GEP->getType()->isVectorTy())
14987         continue;
14988       GEPs[GEP->getPointerOperand()].push_back(GEP);
14989     }
14990   }
14991 }
