14699   unsigned VF = Chain.size();
14700 
14701   if (!isPowerOf2_32(Sz) || !isPowerOf2_32(VF) || VF < 2 || VF < MinVF)
14702     return false;
14703 
14704   LLVM_DEBUG(dbgs() << "SLP: Analyzing " << VF << " stores at offset " << Idx
14705                     << "\n");
14706 
14707   R.buildTree(Chain);
14708   if (R.isTreeTinyAndNotFullyVectorizable())
14709     return false;
14710   if (R.isLoadCombineCandidate())
14711     return false;
14712   R.reorderTopToBottom();
14713   R.reorderBottomToTop();
14714   R.buildExternalUses();
14715 
14716   R.computeMinimumValueSizes();
14717 
14718   InstructionCost Cost = R.getTreeCost();
14719 
14720   LLVM_DEBUG(dbgs() << "SLP: Found cost = " << Cost << " for VF=" << VF << "\n");
14721   if (Cost < -SLPCostThreshold) {
14722     LLVM_DEBUG(dbgs() << "SLP: Decided to vectorize cost = " << Cost << "\n");
14723 
14724     using namespace ore;
14725 
14726     R.getORE()->emit(OptimizationRemark(SV_NAME, "StoresVectorized",
14727                                         cast<StoreInst>(Chain[0]))
14728                      << "Stores SLP vectorized with cost " << NV("Cost", Cost)
14729                      << " and with tree size "
14730                      << NV("TreeSize", R.getTreeSize()));
