14246                                  {I->getOperand(0), I->getOperand(1)});
14247   }
14248   case Instruction::Shl: {
14249     // If we are truncating the result of this SHL, and if it's a shift of an
14250     // inrange amount, we can always perform a SHL in a smaller type.
14251     auto ShlChecker = [&](unsigned BitWidth, unsigned) {
14252       KnownBits AmtKnownBits = computeKnownBits(I->getOperand(1), *DL);
14253       return AmtKnownBits.getMaxValue().ult(BitWidth);
14254     };
14255     return TryProcessInstruction(
14256         I, *ITE, BitWidth, {I->getOperand(0), I->getOperand(1)}, ShlChecker);
14257   }
14258   case Instruction::LShr: {
14259     // If this is a truncate of a logical shr, we can truncate it to a smaller
14260     // lshr iff we know that the bits we would otherwise be shifting in are
14261     // already zeros.
14262     auto LShrChecker = [&](unsigned BitWidth, unsigned OrigBitWidth) {
14263       KnownBits AmtKnownBits = computeKnownBits(I->getOperand(1), *DL);
14264       APInt ShiftedBits = APInt::getBitsSetFrom(OrigBitWidth, BitWidth);
14265       return AmtKnownBits.getMaxValue().ult(BitWidth) &&
14266              MaskedValueIsZero(I->getOperand(0), ShiftedBits,
14267                                SimplifyQuery(*DL));
14268     };
14269     return TryProcessInstruction(
14270         I, *ITE, BitWidth, {I->getOperand(0), I->getOperand(1)}, LShrChecker);
14271   }
14272   case Instruction::AShr: {
14273     // If this is a truncate of an arithmetic shr, we can truncate it to a
14274     // smaller ashr iff we know that all the bits from the sign bit of the
14275     // original type and the sign bit of the truncate type are similar.
14276     auto AShrChecker = [&](unsigned BitWidth, unsigned OrigBitWidth) {
14277       KnownBits AmtKnownBits = computeKnownBits(I->getOperand(1), *DL);
14278       unsigned ShiftedBits = OrigBitWidth - BitWidth;
14279       return AmtKnownBits.getMaxValue().ult(BitWidth) &&
14280              ShiftedBits <
14281                  ComputeNumSignBits(I->getOperand(0), *DL, 0, AC, nullptr, DT);
14282     };
14283     return TryProcessInstruction(
14284         I, *ITE, BitWidth, {I->getOperand(0), I->getOperand(1)}, AShrChecker);
14285   }
14286   case Instruction::UDiv:
14287   case Instruction::URem: {
14288     // UDiv and URem can be truncated if all the truncated bits are zero.
14289     auto Checker = [&](unsigned BitWidth, unsigned OrigBitWidth) {
14290       assert(BitWidth <= OrigBitWidth && "Unexpected bitwidths!");
14291       APInt Mask = APInt::getBitsSetFrom(OrigBitWidth, BitWidth);
14292       return MaskedValueIsZero(I->getOperand(0), Mask, SimplifyQuery(*DL)) &&
14293              MaskedValueIsZero(I->getOperand(1), Mask, SimplifyQuery(*DL));
14294     };
14295     return TryProcessInstruction(I, *ITE, BitWidth,
14296                                  {I->getOperand(0), I->getOperand(1)}, Checker);
14297   }
14298 
14299   // We can demote selects if we can demote their true and false values.
14300   case Instruction::Select: {
14301     Start = 1;
14302     auto *SI = cast<SelectInst>(I);
14303     return TryProcessInstruction(I, *ITE, BitWidth,
14304                                  {SI->getTrueValue(), SI->getFalseValue()});
14305   }
14306 
14307   // We can demote phis if we can demote all their incoming operands. Note that
14308   // we don't need to worry about cycles since we ensure single use above.
14309   case Instruction::PHI: {
14310     PHINode *PN = cast<PHINode>(I);
