14615 bool SLPVectorizerPass::runImpl(Function &F, ScalarEvolution *SE_,
14616                                 TargetTransformInfo *TTI_,
14617                                 TargetLibraryInfo *TLI_, AAResults *AA_,
14618                                 LoopInfo *LI_, DominatorTree *DT_,
14619                                 AssumptionCache *AC_, DemandedBits *DB_,
14620                                 OptimizationRemarkEmitter *ORE_) {
14621   if (!RunSLPVectorization)
14622     return false;
14623   SE = SE_;
14624   TTI = TTI_;
14625   TLI = TLI_;
14626   AA = AA_;
14627   LI = LI_;
14628   DT = DT_;
14629   AC = AC_;
14630   DB = DB_;
14631   DL = &F.getParent()->getDataLayout();
14632 
14633   Stores.clear();
14634   GEPs.clear();
14635   bool Changed = false;
14636 
14637   // If the target claims to have no vector registers don't attempt
14638   // vectorization.
14639   if (!TTI->getNumberOfRegisters(TTI->getRegisterClassForType(true))) {
14640     LLVM_DEBUG(
14641         dbgs() << "SLP: Didn't find any vector registers for target, abort.\n");
14642     return false;
14643   }
14644 
14645   // Don't vectorize when the attribute NoImplicitFloat is used.
14646   if (F.hasFnAttribute(Attribute::NoImplicitFloat))
14647     return false;
14648 
14649   LLVM_DEBUG(dbgs() << "SLP: Analyzing blocks in " << F.getName() << ".\n");
14650 
14651   // Use the bottom up slp vectorizer to construct chains that start with
14652   // store instructions.
14653   BoUpSLP R(&F, SE, TTI, TLI, AA, LI, DT, AC, DB, DL, ORE_);
14654 
14655   // A general note: the vectorizer must use BoUpSLP::eraseInstruction() to
14656   // delete instructions.
14657 
14658   // Update DFS numbers now so that we can use them for ordering.
14659   DT->updateDFSNumbers();
14660 
14661   // Scan the blocks in the function in post order.
14662   for (auto *BB : post_order(&F.getEntryBlock())) {
14663     // Start new block - clear the list of reduction roots.
14664     R.clearReductionData();
14665     collectSeedInstructions(BB);
14666 
14667     // Vectorize trees that end at stores.
14668     if (!Stores.empty()) {
14669       LLVM_DEBUG(dbgs() << "SLP: Found stores for " << Stores.size()
14670                         << " underlying objects.\n");
14671       Changed |= vectorizeStoreChains(R);
14672     }
14673 
14674     // Vectorize trees that end at reductions.
14675     Changed |= vectorizeChainsInBlock(BB, R);
14676 
14677     // Vectorize the index computations of getelementptr instructions. This
14678     // is primarily intended to catch gather-like idioms ending at
14679     // non-consecutive loads.
14680     if (!GEPs.empty()) {
14681       LLVM_DEBUG(dbgs() << "SLP: Found GEPs for " << GEPs.size()
14682                         << " underlying objects.\n");
14683       Changed |= vectorizeGEPIndices(BB, R);
14684     }
